async function main() {
  console.log("Seeding 10 IELTS listening practice tests...");
  let created = 0;
  for (const t of tests) {
    const existing = await db.listeningTest.findFirst({ where: { title: t.title } });
    if (existing) { console.log(`Skipping (already exists): ${t.title}`); continue; }
    await db.listeningTest.create({
      data: {
        title: t.title,
        description: t.description,
        audioUrl: t.audioUrl,
        difficulty: "MEDIUM",
        isPublished: t.isPublished,
        sections: {
          create: t.sections.map((s: any) => ({
            sectionNum: s.sectionNum,
            title: s.title ?? null,
            questions: {
              create: s.questions.map((q: any) => ({
                questionNum: q.questionNum,
                type: q.type,
                prompt: q.prompt,
                options: q.options ? JSON.stringify(q.options) : null,
                correctAnswer: q.correctAnswer,
                explanation: q.explanation ?? null,
              })),
            },
          })),
        },
      },
    });
    console.log(`✓ Created: ${t.title}`);
    created++;
  }
  console.log(`\nDone — ${created} tests created.`);
  await db.$disconnect();
}

main().catch((e) => { console.error(e); process.exit(1); });
